"""Накопление токенов, cache hits и счётчика API по ответам LLM в этапах пайплайна."""from __future__ import annotationsfrom typing import TypedDictclass LLMUsageAcc(TypedDict):    prompt: int    reasoning: int    completion: int    total: int    cache_hits: int    api_calls: intdef empty_llm_usage_acc() -> LLMUsageAcc:    return {        "prompt": 0,        "reasoning": 0,        "completion": 0,        "total": 0,        "cache_hits": 0,        "api_calls": 0,    }def accumulate_llm_usage(acc: LLMUsageAcc, response: object) -> None:    """Добавляет токены/API/кеш из ответа LLM."""    cache = bool(getattr(response, "cache", False))    if cache:        acc["cache_hits"] += 1        return    acc["api_calls"] += 1    u = getattr(response, "tokens_usage", None)    if u is None:        return    pr = int(u.prompt)    reas = int(u.reasoning)    comp = int(u.completion)    tot = int(u.total)    if tot <= 0:        tot = pr + reas + comp    acc["prompt"] += pr    acc["reasoning"] += reas    acc["completion"] += comp    acc["total"] += tot